from dataclasses import dataclass, field
from datetime import date
from typing import Optional


@dataclass
class CoPHealthCheck:
    cop_name: str
    assessment_date: date
    active_members: int
    total_certified_practitioners: int
    sessions_last_quarter: int
    avg_attendance: float               # fraction of active members
    async_questions_answered_pct: float # pct answered within SLA
    knowledge_assets_updated_last_90d: int
    use_cases_surfaced_last_quarter: int
    executive_sponsor_attended_last_quarter: bool

    @property
    def active_member_rate(self) -> float:
        if self.total_certified_practitioners == 0:
            return 0.0
        return self.active_members / self.total_certified_practitioners

    def health_score(self) -> dict[str, str]:
        scores = {}

        # Membership vitality
        rate = self.active_member_rate
        if rate >= 0.60:
            scores["membership_vitality"] = "GREEN"
        elif rate >= 0.40:
            scores["membership_vitality"] = "AMBER"
        else:
            scores["membership_vitality"] = "RED"

        # Session cadence
        if self.sessions_last_quarter >= 3 and self.avg_attendance >= 0.50:
            scores["session_health"] = "GREEN"
        elif self.sessions_last_quarter >= 2:
            scores["session_health"] = "AMBER"
        else:
            scores["session_health"] = "RED"

        # Knowledge freshness
        if self.knowledge_assets_updated_last_90d >= 3:
            scores["knowledge_freshness"] = "GREEN"
        elif self.knowledge_assets_updated_last_90d >= 1:
            scores["knowledge_freshness"] = "AMBER"
        else:
            scores["knowledge_freshness"] = "RED"

        # Peer support
        if self.async_questions_answered_pct >= 0.80:
            scores["peer_support"] = "GREEN"
        elif self.async_questions_answered_pct >= 0.60:
            scores["peer_support"] = "AMBER"
        else:
            scores["peer_support"] = "RED"

        # Sponsor engagement
        scores["sponsor_engagement"] = (
            "GREEN" if self.executive_sponsor_attended_last_quarter else "AMBER"
        )

        return scores

    def overall_status(self) -> str:
        scores = self.health_score()
        reds = sum(1 for v in scores.values() if v == "RED")
        ambers = sum(1 for v in scores.values() if v == "AMBER")
        if reds >= 2:
            return "RED -- CoP at risk of collapse; intervention required"
        elif reds == 1 or ambers >= 3:
            return "AMBER -- CoP showing strain; steward review needed"
        return "GREEN -- CoP healthy"

    def interventions(self) -> list[str]:
        scores = self.health_score()
        actions = []
        if scores["membership_vitality"] in ("AMBER", "RED"):
            actions.append(
                "Run membership drive: direct outreach to uncertified practitioners; "
                "offer buddy onboarding for new joiners"
            )
        if scores["session_health"] in ("AMBER", "RED"):
            actions.append(
                "Review session format and timing; survey members on barriers to attendance; "
                "consider shorter focused sessions over one long monthly"
            )
        if scores["knowledge_freshness"] in ("AMBER", "RED"):
            actions.append(
                "Assign knowledge asset owner to each asset; set 90-day review reminder; "
                "add knowledge update as standing agenda item"
            )
        if scores["peer_support"] in ("AMBER", "RED"):
            actions.append(
                "Assign triage role to working group lead; set explicit SLA on async responses; "
                "reward consistent responders in quarterly showcase"
            )
        return actions


check = CoPHealthCheck(
    cop_name="Enterprise GenAI Practitioners CoP",
    assessment_date=date(2026, 10, 1),
    active_members=34,
    total_certified_practitioners=62,
    sessions_last_quarter=3,
    avg_attendance=0.55,
    async_questions_answered_pct=0.73,
    knowledge_assets_updated_last_90d=2,
    use_cases_surfaced_last_quarter=1,
    executive_sponsor_attended_last_quarter=True,
)

print(f"CoP Health Check: {check.cop_name}")
print(f"Active member rate: {check.active_member_rate:.0%} ({check.active_members}/{check.total_certified_practitioners})")
print()
for dimension, status in check.health_score().items():
    print(f"  {dimension}: {status}")
print()
print(f"Overall: {check.overall_status()}")
print()
interventions = check.interventions()
if interventions:
    print("Recommended interventions:")
    for i in interventions:
        print(f"  -> {i}")
